        "title": "SINGAPO人: Discovering Chinese Singaporean Culture",
        "startDateTime": "2026-07-16T10:00:00+08:00",
        "endDateTime": "2026-07-16T20:00:00+08:00",
        "dateText": "2026-07-16",
