        "id": "merged:06dbf154650d1b94a10a1ea23587205825da814d3f6286d73bd7e864b53e4076",
        "title": "<p>Art of Caricature with Cartoon.SG</p>",
        "startDateTime": "Sat, 11 Apr 2026",
        "endDateTime": "Fri, 31 Jul 2026",
        "dateText": "Sat, 11 Apr - Fri, 31 Jul 2026",
